var test = require('tape')
var pull = require('../')

test('filtered randomnes', function (t) {
  pull(
    pull.infinite(),
    pull.filter(function (d) {
      if (process.env.TEST_VERBOSE) console.log('f', d)
      return d > 0.5
    }),
